VALUES
  (4, 6, 4, 2.00, 2, 'Se cuenta con un análisis de contexto interno y externo (marco legal electoral, normativa de protección de datos, infraestructura TI, partes interesadas) que sustenta la planificación del SGSI, aunque su actualización no sigue aún una periodicidad formal.', 'Definir una periodicidad semestral de revisión del análisis de contexto y formalizarla en el procedimiento del SGSI, incorporando los resultados a las actas del Comité SGSI.', 4, 1, 1, now(), false, 1),
  (4, 7, 5, 1.00, 9, 'Se ha iniciado la identificación de partes interesadas (entes reguladores, ciudadanía, proveedores TI, otras entidades del Estado), pero aún no existe un registro formal ni un análisis sistemático de sus requisitos.', 'Elaborar y mantener un registro formal de partes interesadas del SGSI, con sus requisitos identificados y su relación con los controles aplicables.', 4, 1, 1, now(), false, 1),
  (4, 11, 3, 3.00, 2, 'El alcance del SGSI está definido y documentado, cubriendo la infraestructura tecnológica de la sede central; se ejecuta con una frecuencia de revisión establecida.', 'Incorporar en la próxima revisión del alcance los cambios organizacionales recientes y validar su vigencia con el Comité SGSI.', 4, 1, 1, now(), false, 1),
  (4, 12, 3, 3.00, 2, 'La Alta Dirección demuestra compromiso con el SGSI mediante la asignación de responsables, participación en el Comité SGSI y comunicación de la importancia de la seguridad de la información.', 'Documentar formalmente la participación de la Alta Dirección en las revisiones del SGSI mediante actas firmadas.', 4, 1, 1, now(), false, 1),
  (4, 18, 4, 2.00, 12, 'El SGSI se encuentra establecido e implementado, con procesos de gestión, operación y mejora en ejecución, aunque el ciclo de mejora continua no está aún completamente institucionalizado.', 'Formalizar el ciclo PHVA del SGSI en un procedimiento único que integre planificación, revisión por la dirección y acciones de mejora.', 4, 1, 1, now(), false, 1),
  (4, 19, 3, 3.00, 2, 'La Alta Dirección demuestra compromiso con el SGSI mediante la asignación de responsables, participación en el Comité SGSI y comunicación de la importancia de la seguridad de la información.', 'Documentar formalmente la participación de la Alta Dirección en las revisiones del SGSI mediante actas firmadas.', 4, 1, 1, now(), false, 1),
